var fontPopup     = document.getElementById('font-popup');
var fontSearch    = document.getElementById('font-search');
var fontList      = document.getElementById('font-list');
var fontSelectBtn = document.getElementById('font-select-btn');
var fontSelectLabel = document.getElementById('font-select-label');

function buildFontList(query) {
  var q = (query || '').toLowerCase();
  var filtered = PRESET_FONTS.filter(function(f) {
    return !q || f.name.toLowerCase().includes(q) || f.value.toLowerCase().includes(q);
  });

  var groups = {};
  filtered.forEach(function(f) {
    if (!groups[f.group]) groups[f.group] = [];
    groups[f.group].push(f);
  });

  fontList.innerHTML = '';

  var browserFonts = [];
  try {
    document.fonts.forEach(function(ff) {
      var n = ff.family.replace(/['"]/g, '');
      if (!q || n.toLowerCase().includes(q)) browserFonts.push(n);
    });
    browserFonts = [...new Set(browserFonts)].sort();
  } catch(e) {}

  Object.keys(groups).forEach(function(group) {
    var label = document.createElement('div');
    label.className = 'font-section-label';
    label.textContent = group;
    fontList.appendChild(label);
    groups[group].forEach(function(f) { appendFontItem(f.name, f.value); });
  });

  if (browserFonts.length) {
    var label = document.createElement('div');
    label.className = 'font-section-label';
    label.textContent = 'Loaded in browser';
    fontList.appendChild(label);
    browserFonts.forEach(function(name) {
      appendFontItem(name, name);
    });
  }
}

function appendFontItem(name, value) {
  var item = document.createElement('button');
  item.type = 'button';
  item.setAttribute('role', 'option');
  item.setAttribute('aria-selected', cfgFont === value ? 'true' : 'false');
  item.className = 'font-item' + (cfgFont === value ? ' active' : '');
  var previewSpan = document.createElement('span');
  previewSpan.className = 'font-item-preview';
  previewSpan.style.fontFamily = value + ', sans-serif';
  previewSpan.textContent = 'Aa';
  var nameSpan = document.createElement('span');
  nameSpan.className = 'font-item-name';
  nameSpan.textContent = name;
  item.appendChild(previewSpan);
  item.appendChild(nameSpan);
  item.addEventListener('click', function() {
    cfgFont = value;
    fontSelectLabel.textContent = name;
    closeFontPopup();
    readConfig();
    scheduleRender(0);
    fontSelectBtn.focus();
  });
  fontList.appendChild(item);
}

var fontPopupController = createPopupController({
  popup: fontPopup,
  trigger: fontSelectBtn,
  visibility: { focusSelector: '#font-search' },
  beforeOpen: function() {
    buildFontList('');
    fontSearch.value = '';
    positionAnchoredPopup(fontPopup, fontSelectBtn, { width: 220, height: 320 });
  },
  contains: function(target) {
    return !!(target.closest('#font-popup') || target.closest('#font-select-btn'));
  },
  repositionOnResize: true,
  position: function() { positionAnchoredPopup(fontPopup, fontSelectBtn, { width: 220, height: 320 }); },
});

function openFontPopup() {
  fontPopupController.open({ focusFirst: true });
}

function closeFontPopup(restoreFocus) {
  fontPopupController.close({ restoreFocus: !!restoreFocus });
}

fontSearch.addEventListener('input', function() {
  buildFontList(fontSearch.value);
});

var paddingNum    = document.getElementById('cfg-padding');
var paddingSlider = document.getElementById('cfg-padding-slider');

function setPadding(val) {
  val = Math.max(0, Math.min(120, parseInt(val, 10) || 0));
  cfgPadding = val;
  paddingNum.value    = val;
  paddingSlider.value = val;
  readConfig();
  scheduleRender(200);
}

paddingNum.addEventListener('input', function() { setPadding(paddingNum.value); });
paddingSlider.addEventListener('input', function() { setPadding(paddingSlider.value); });


var currentLeftPanel = 'code';
var currentMobilePanel = 'code';

function setMobilePanel(panel) {
  currentMobilePanel = panel;
  document.body.dataset.mobilePanel = panel;
  syncModeButtons();
}

function setLeftPanelMode(panel) {
  currentLeftPanel = panel === 'config' ? 'config' : 'code';
  if (currentLeftPanel === 'code') {
    editorView.hidden = false;
    editorView.style.display = 'flex';
    configView.hidden = true;
    configView.classList.remove('visible');
    configView.setAttribute('aria-hidden', 'true');
    editorView.setAttribute('aria-hidden', 'false');
  } else {
    editorView.hidden = true;
    editorView.style.display = 'none';
    configView.hidden = false;
    configView.classList.add('visible');
    configView.setAttribute('aria-hidden', 'false');
    editorView.setAttribute('aria-hidden', 'true');
    refreshAllColorUIs();
  }
  syncModeButtons();
}

function syncModeButtons() {
  document.querySelectorAll('[data-left-panel]').forEach(function(btn) {
    var active = btn.dataset.leftPanel === currentLeftPanel;
    btn.classList.toggle('is-active', active);
    btn.setAttribute('aria-pressed', active ? 'true' : 'false');
  });
  document.querySelectorAll('[data-mobile-panel]').forEach(function(btn) {
    var active = btn.dataset.mobilePanel === currentMobilePanel;
    btn.classList.toggle('is-active', active);
    btn.setAttribute('aria-pressed', active ? 'true' : 'false');
  });
}

function activateModeButton(button, focusButton) {
  // Source/Style carry data-left-panel (+ data-mobile-panel); Preview carries
  // only data-mobile-panel. One handler drives both the desktop left-panel tab
  // and the mobile whole-view switch from the same adaptive control.
  var left = button.dataset.leftPanel;
  var mobile = button.dataset.mobilePanel || left;
  if (left) setLeftPanelMode(left);
  else if (mobile === 'code' || mobile === 'config') setLeftPanelMode(mobile);
  if (mobile) setMobilePanel(mobile);
  if (focusButton) button.focus();
}

function visibleSegmentButtons(group) {
  // offsetParent is null for display:none buttons (e.g. Preview on desktop),
  // so arrow-key nav only cycles the options actually on screen.
  return Array.prototype.slice.call(group.querySelectorAll('.mode-option')).filter(function(b) {
    return b.offsetParent !== null;
  });
}

function moveWithinSegmentedControl(button, direction) {
  var group = button.closest('[data-segmented-control]');
  if (!group) return;
  var buttons = visibleSegmentButtons(group);
  var index = buttons.indexOf(button);
  if (index < 0) return;
  var nextIndex = index;
  if (direction === 'Home') nextIndex = 0;
  else if (direction === 'End') nextIndex = buttons.length - 1;
  else nextIndex = (index + (direction === 'ArrowRight' ? 1 : -1) + buttons.length) % buttons.length;
  var next = buttons[nextIndex];
  if (next) activateModeButton(next, true);
}

document.querySelectorAll('[data-segmented-control] .mode-option').forEach(function(button) {
  button.addEventListener('click', function() { activateModeButton(button, false); });
  button.addEventListener('keydown', function(e) {
    if (!["ArrowLeft", "ArrowRight", "Home", "End"].includes(e.key)) return;
    e.preventDefault();
    moveWithinSegmentedControl(button, e.key);
  });
});

